import{_ as a,o as t,c as o,a4 as i}from"./chunks/framework.DkKDtR5x.js";const m=JSON.parse('{"title":"Devops","description":"","frontmatter":{},"headers":[],"relativePath":"devops/index.md","filePath":"devops/index.md"}'),n={name:"devops/index.md"};function s(r,e,l,p,c,d){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="devops" tabindex="-1">Devops <a class="header-anchor" href="#devops" aria-label="Permalink to “Devops”">​</a></h1><p>DevOps is a software development approach that emphasizes collaboration, automation, and continuous integration and delivery (CI/CD) to streamline the process of developing, testing, and deploying software.</p><p>It aims to break down the traditional silos between development and operations teams, fostering a culture of shared responsibility and faster, more reliable software releases.</p><p><img src="https://www.pagerduty.com/wp-content/uploads/2020/11/6-essential-DevOps-roles_DevOps-1024x536.png" alt="CICD"></p><h2 id="culture" tabindex="-1">Culture <a class="header-anchor" href="#culture" aria-label="Permalink to “Culture”">​</a></h2><p>DevOps promotes a culture of collaboration, communication, and shared responsibility between development and operations teams.</p><h2 id="practices" tabindex="-1">Practices: <a class="header-anchor" href="#practices" aria-label="Permalink to “Practices:”">​</a></h2><ul><li>DevOps utilizes various practices, including:</li><li>Continuous Integration (CI): Regularly merging code changes into a central repository and running automated tests.</li><li>Continuous Delivery (CD): Automating the release process to ensure code can be deployed to production at any time.</li><li>Infrastructure as Code: Managing infrastructure using code, enabling automation and consistency.</li><li>Automation: Automating repetitive tasks to improve efficiency and reduce errors.</li><li>Monitoring and Feedback: Continuously monitoring application performance and gathering feedback to identify areas for improvement.</li></ul><h2 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to “Tools”">​</a></h2><p>DevOps relies on various tools to support its practices, such as:</p><ul><li>Version control systems (e.g., Git)</li><li>CI/CD platforms (e.g., <a href="./jenkins">Jenkins</a>, Azure DevOps)</li><li>Containerization technologies (e.g., Docker, Kubernetes)</li><li>Configuration management tools (e.g., Ansible, Puppet)</li><li>Monitoring and logging tools (e.g., Prometheus, Grafana)</li></ul>',11)])])}const g=a(n,[["render",s]]);export{m as __pageData,g as default};
